// --- SQL Validation & Sanitization ---

sealed trait ValidationError
case class ForbiddenOperationError(operation: String) extends ValidationError
case class ForbiddenTableError(table: String) extends ValidationError
case class ForbiddenFunctionError(function: String) extends ValidationError
case class SqlParseError(message: String) extends ValidationError
case class DangerousPatternError(pattern: String) extends ValidationError
case class RowLimitExceededError(requested: Int, max: Int) extends ValidationError

object QueryValidator {

  // Dangerous SQL patterns that should NEVER be allowed from user input
  private val DANGEROUS_PATTERNS: List[(String, String)] = List(
    ("""(?i)\b(DROP|ALTER|CREATE|TRUNCATE|DELETE|UPDATE|INSERT|MERGE|REPLACE)\b""", "DDL/DML operation"),
    ("""(?i)\b(GRANT|REVOKE|DENY)\b""", "permission modification"),
    ("""(?i)\b(EXEC|EXECUTE|CALL|SYSTEM)\b""", "procedure execution"),
    ("""(?i)\b(INTO\s+OUTFILE|INTO\s+DUMPFILE|LOAD_FILE)\b""", "file operation"),
    ("""(?i)\b(INFORMATION_SCHEMA|SYS\.|MYSQL\.|PG_)""", "system schema access"),
    ("""(?i)(--|#|/\*|\*/|;)""", "SQL comment or statement terminator"),
    ("""(?i)\b(UNION\s+ALL\s+SELECT|UNION\s+SELECT)\b""", "UNION injection"),
    ("""(?i)\b(SLEEP|BENCHMARK|WAITFOR|PG_SLEEP)\b""", "time-based injection"),
    ("""(?i)\b(LOAD\s+DATA|COPY\s+FROM|COPY\s+TO)\b""", "data load/export"),
    ("""(?i)\b(SET\s+|RESET\s+)""", "configuration modification"),
    ("""(?i)\b(ADD\s+JAR|ADD\s+FILE|ADD\s+ARCHIVE)\b""", "resource injection"),
    ("""(?i)\b(UNCACHE|CACHE\s+TABLE|REFRESH)\b""", "cache manipulation"),
    ("""(?i)\b(EXPLAIN|DESCRIBE|SHOW\s+TABLES|SHOW\s+DATABASES)\b""", "metadata exploration"),
    ("""(?i)\b(CREATE\s+(TEMP|TEMPORARY)\s+(TABLE|VIEW|FUNCTION))\b""", "temp object creation"),
  )

  // Dangerous Spark SQL functions
  private val DANGEROUS_FUNCTIONS: Set[String] = Set(
    "java_method", "reflect", "stack",
    "input_file_name", "input_file_block_start", "input_file_block_length",
    "current_user", "current_database",
    "assert_true", "raise_error",
    "unhex", "encode", "decode",
    "from_json", "schema_of_json", // can be used for inference attacks
    "xpath", "xpath_string", "xpath_boolean", // XXE potential
  ).map(_.toLowerCase)

  def validate(sql: String, permissions: UserPermissions): Either[List[ValidationError], String] = {
    val errors = scala.collection.mutable.ListBuffer[ValidationError]()

    // 1. Check for null/empty
    val trimmedSql = sql.trim
    if (trimmedSql.isEmpty) {
      return Left(List(SqlParseError("Empty query")))
    }

    // 2. Length check
    if (trimmedSql.length > 10000) {
      return Left(List(SqlParseError("Query exceeds maximum length of 10000 characters")))
    }

    // 3. Pattern-based dangerous SQL detection
    DANGEROUS_PATTERNS.foreach { case (pattern, description) =>
      if (pattern.r.findFirstIn(trimmedSql).isDefined) {
        errors += DangerousPatternError(s"Forbidden pattern detected: $description")
      }
    }

    if (errors.nonEmpty) {
      return Left(errors.toList)
    }

    // 4. Parse the SQL using Spark's Catalyst parser for AST-level validation
    val parsedPlan = Try(CatalystSqlParser.parsePlan(trimmedSql))
    parsedPlan match {
      case Failure(ex) =>
        return Left(List(SqlParseError(s"Invalid SQL syntax: ${ex.getMessage.take(200)}")))
      case Success(plan) =>
        // 5. Validate only SELECT operations are used
        validatePlanOperations(plan, permissions, errors)

        // 6. Validate table references against allowed tables
        validateTableReferences(plan, permissions, errors)

        // 7. Check for dangerous function calls in expressions
        validateFunctions(trimmedSql, errors)
    }

    if (errors.nonEmpty) Left(errors.toList) else Right(trimmedSql)
  }

  private def validatePlanOperations(
    plan: LogicalPlan,
    permissions: UserPermissions,
    errors: scala.collection.mutable.ListBuffer[ValidationError]
  ): Unit = {
    plan match {
      case _: Command =>
        errors += ForbiddenOperationError("Commands are not allowed, only SELECT queries")
      case _ =>
        // Check it's a query plan (Project, Filter, Join, Aggregate, etc.)
        // Walk the plan tree to ensure no writes
        plan.foreach {
          case _: InsertIntoStatement =>
            errors += ForbiddenOperationError("INSERT is not allowed")
          case _: Command =>
            errors += ForbiddenOperationError("Commands are not allowed")
          case _ => // OK - read operations
        }
    }
  }

  private def validateTableReferences(
    plan: LogicalPlan,
    permissions: UserPermissions,
    errors: scala.collection.mutable.ListBuffer[ValidationError]
  ): Unit = {
    plan.foreach {
      case UnresolvedRelation(multipartIdentifier, _, _) =>
        val tableName = multipartIdentifier.mkString(".")
        val fullyQualified = if (multipartIdentifier.size == 1) {
          // Assume default allowed database prefix
          s"analytics.${multipartIdentifier.head}"
        } else {
          tableName
        }

        if (!permissions.allowedTables.contains(fullyQualified.toLowerCase)) {
          errors += ForbiddenTableError(
            s"Access denied to table: $tableName. You have access to: ${permissions.allowedTables.mkString(", ")}"
          )
        }
      case _ =>
    }
  }

  private def validateFunctions(
    sql: String,
    errors: scala.collection.mutable.ListBuffer[ValidationError]
  ): Unit = {
    val functionCallPattern = """(?i)(\w+)\s*\(""".r
    functionCallPattern.findAllMatchIn(sql).foreach { m =>
      val funcName = m.group(1).toLowerCase
      if (DANGEROUS_FUNCTIONS.contains(funcName)) {
        errors += ForbiddenFunctionError(s"Function '$funcName' is not allowed")
      }
    }
  }
}

// --- Query Execution Engine ---

class SecureQueryExecutor(spark: SparkSession) {

  private val queryExecutor = Executors.newFixedThreadPool(
    Runtime.getRuntime.availableProcessors()
  )

  // Audit log for all query attempts
  def auditLog(
    queryId: String,
    userId: String,
    sql: String,
    status: String,
    error: Option[String] = None
  ): Unit = {
    val timestamp = Instant.now().toString
    // In production, write to a secure audit log (e.g., append-only table, SIEM)
    println(s"AUDIT | $timestamp | queryId=$queryId | userId=$userId | status=$status | " +
      s"error=${error.getOrElse("none")} | sql=${sql.take(500)}")
  }

  def executeQuery(
    request: QueryRequest,
    permissions: UserPermissions
  ): Future[QueryResponse] = {
    val queryId = UUID.randomUUID().toString
    val startTime = System.currentTimeMillis()

    implicit val ec: ExecutionContext = ExecutionContext.fromExecutor(queryExecutor)

    Future {
      // Step 1: Validate the query
      QueryValidator.validate(request.sql, permissions) match {
        case Left(errors) =>
          val errorMsg = errors.map {
            case ForbiddenOperationError(op) => s"Forbidden operation: $op"
            case ForbiddenTableError(table) => s"Forbidden table: $table"
            case ForbiddenFunctionError(func) => s"Forbidden function: $func"
            case SqlParseError(msg) => s"Parse error: $msg"
            case DangerousPatternError(p) => s"Dangerous pattern: $p"
            case RowLimitExceededError(req, max) => s"Row limit exceeded: $req > $max"
          }.mkString("; ")

          auditLog(queryId, request.userId, request.sql, "REJECTED", Some(errorMsg))

          QueryResponse(
            queryId = queryId,
            status = "REJECTED",
            columns = None,
            data = None,
            rowCount = None,
            error = Some(s"Query validation failed: $errorMsg"),
            executionTimeMs = Some(System.currentTimeMillis() - startTime)
          )

        case Right(validatedSql) =>
          // Step 2: Apply row limit
          val maxRows = math.min(
            request.maxRows.getOrElse(permissions.maxRowsLimit),
            permissions.maxRowsLimit
          )
          val limitedSql = applyRowLimit(validatedSql, maxRows)

          // Step 3: Execute with timeout and resource constraints
          try {
            auditLog(queryId, request.userId, limitedSql, "EXECUTING")

            val result = executeWithTimeout(
              limitedSql,
              permissions.queryTimeoutSeconds,
              queryId,
              request.userId
            )

            val columns = result.columns.toList
            val data = result.collect().map(row =>
              (0 until row.length).map(i =>
                Option(row.get(i)).map(_.toString).getOrElse("null")
              ).toList
            ).toList

            auditLog(queryId, request.userId, limitedSql, "SUCCESS")

            QueryResponse(
              queryId = queryId,
              status = "SUCCESS",
              columns = Some(columns),
              data = Some(data),
              rowCount = Some(data.length),
              error = None,
              executionTimeMs = Some(System.currentTimeMillis() - startTime)
            )
          } catch {
            case _: TimeoutException =>
              // Cancel the Spark job
              spark.sparkContext.cancelJobGroup(queryId)
              auditLog(queryId, request.userId, limitedSql, "TIMEOUT")

              QueryResponse(
                queryId = queryId,
                status = "TIMEOUT",
                columns = None,
                data = None,
                rowCount = None,
                error = Some(s"Query exceeded timeout of ${permissions.queryTimeoutSeconds} seconds"),
                executionTimeMs = Some(System.currentTimeMillis() - startTime)
              )

            case ex: Exception =>
              auditLog(queryId, request.userId, limitedSql, "ERROR", Some(ex.getMessage.take(500)))

              QueryResponse(
                queryId = queryId,
                status = "ERROR",
                columns = None,
                data = None,
                rowCount = None,
                // Never expose internal error details to users
                error = Some(s"Query execution failed. Reference: $queryId"),
                executionTimeMs = Some(System.currentTimeMillis() - startTime)
              )
          }
      }
    }
  }

  private def applyRowLimit(sql: String, maxRows: Int): String = {
    // Wrap the user query with an outer LIMIT to enforce row cap
    s"SELECT * FROM ($sql) __limited_result LIMIT $maxRows"
  }

  private def executeWithTimeout(
    sql: String,
    timeoutSeconds: Int,
    queryId: String,
    userId: String
  ): DataFrame = {
    // Set job group for cancellation capability
    spark.sparkContext.setJobGroup(queryId, s"User query from $userId", interruptOnCancel = true)

    // Set per-query resource limits via Spark fair scheduler
    spark.sparkContext.setLocalProperty("spark.scheduler.pool", "user_queries")

    try {
      // Use Spark's SQL execution with the validated query
      val df = spark.sql(sql)

      // Force evaluation within timeout
      val future = java.util.concurrent.CompletableFuture.supplyAsync(
        () => {
          // Materialize the result
          df.collect()
          df
        },
        queryExecutor
      )

      future.get(timeoutSeconds.toLong, TimeUnit.SECONDS)
    } finally {
      spark.sparkContext.clearJobGroup()
    }
  }

  def shutdown(): Unit = {
    queryExecutor.shutdown()
    queryExecutor.awaitTermination(30, TimeUnit.SECONDS)
  }
}

