// --- Rate Limiter ---

class RateLimiter(maxRequestsPerMinute: Int) {
  private val requestCounts = new java.util.concurrent.ConcurrentHashMap[String, java.util.concurrent.atomic.AtomicInteger]()
  private val windowStart = new java.util.concurrent.ConcurrentHashMap[String, Long]()

  def allowRequest(userId: String): Boolean = {
    val now = System.currentTimeMillis()
    val windowMs = 60000L

    windowStart.putIfAbsent(userId, now)
    requestCounts.putIfAbsent(userId, new java.util.concurrent.atomic.AtomicInteger(0))

    val start = windowStart.get(userId)
    if (now - start > windowMs) {
      windowStart.put(userId, now)
      requestCounts.put(userId, new java.util.concurrent.atomic.AtomicInteger(1))
      true
    } else {
      requestCounts.get(userId).incrementAndGet() <= maxRequestsPerMinute
    }
  }
}

// --- Main Application ---

object SecureAnalyticsPlatform extends App {

  import JsonProtocols._

  // Initialize Spark with security configurations
  val spark = SparkSession.builder()
    .appName("Secure Analytics Platform")
    .master("local[*]")
    // Security configurations
    .config("spark.sql.optimizer.excludedRules",
      "org.apache.spark.sql.catalyst.optimizer.PushDownPredicate")
    .config("spark.sql.adaptive.enabled", "true")
    .config("spark.sql.adaptive.coalescePartitions.enabled", "true")
    // Resource limits for user queries
    .config("spark.sql.autoBroadcastJoinThreshold", "10m")
    .config("spark.sql.shuffle.partitions", "50")
    // Disable dangerous features
    .config("spark.sql.hive.convertMetastoreParquet", "true")
    .getOrCreate()

  // Set log level
  spark.sparkContext.setLogLevel("WARN")

  // Create sample data for demonstration
  setupSampleData(spark)

  // Initialize components
  val queryExecutor = new SecureQueryExecutor(spark)
  val rateLimiter = new RateLimiter(maxRequestsPerMinute = 30)

  // Start HTTP API
  implicit val system: ActorSystem = ActorSystem("analytics-api")
  implicit val ec: ExecutionContext = system.dispatcher

  val route =
    pathPrefix("api" / "v1") {
      path("query") {
        post {
          entity(as[QueryRequest]) { request =>
            // 1. Authentication (simplified - use proper JWT/OAuth in production)
            val userId = request.userId
            if (userId == null || userId.trim.isEmpty) {
              complete(StatusCodes.Unauthorized -> QueryResponse(
                queryId = "", status = "UNAUTHORIZED",
                columns = None, data = None, rowCount = None,
                error = Some("Authentication required"),
                executionTimeMs = None
              ))
            }
            // 2. Rate limiting
            else if (!rateLimiter.allowRequest(userId)) {
              complete(StatusCodes.TooManyRequests -> QueryResponse(
                queryId = "", status = "RATE_LIMITED",
                columns = None, data = None, rowCount = None,
                error = Some("Rate limit exceeded. Please try again later."),
                executionTimeMs = None
              ))
            }
            else {
              // 3. Authorization
              PermissionService.getPermissions(userId) match {
                case None =>
                  complete(StatusCodes.Forbidden -> QueryResponse(
                    queryId = "", status = "FORBIDDEN",
                    columns = None, data = None, rowCount = None,
                    error = Some("User not authorized for query execution"),
                    executionTimeMs = None
                  ))
                case Some(permissions) =>
                  // 4. Execute with full validation
                  val resultFuture = queryExecutor.executeQuery(request, permissions)
                  onComplete(resultFuture) {
                    case Success(response) =>
                      val statusCode = response.status match {
                        case "SUCCESS" => StatusCodes.OK
                        case "REJECTED" => StatusCodes.BadRequest
                        case "TIMEOUT" => StatusCodes.GatewayTimeout
                        case _ => StatusCodes.InternalServerError
                      }
                      complete(statusCode -> response)
                    case Failure(ex) =>
                      complete(StatusCodes.InternalServerError -> QueryResponse(
                        queryId = "", status = "ERROR",
                        columns = None, data = None, rowCount = None,
                        error = Some("Internal server error"),
                        executionTimeMs = None
                      ))
                  }
              }
            }
          }
        }
      } ~
      path("health") {
        get {
          complete(StatusCodes.OK -> """{"status":"healthy"}""")
        }
      }
    }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)
  println("Secure Analytics Platform running on http://0.0.0.0:8080")
  println("POST /api/v1/query - Execute a validated SQL query")

  // Graceful shutdown
  sys.addShutdownHook {
    queryExecutor.shutdown()
    spark.stop()
    system.terminate()
  }

  def setupSampleData(spark: SparkSession): Unit = {
    import spark.implicits._

    // Create sample analytics tables
    val userEvents = Seq(
      (1, "click", "2024-01-15", "homepage"),
      (2, "view", "2024-01-15", "product"),
      (3, "click", "2024-01-16", "checkout"),
      (1, "purchase", "2024-01-16", "checkout"),
      (4, "view", "2024-01-17", "homepage")
    ).toDF("user_id", "event_type", "event_date", "page")

    val pageViews = Seq(
      ("homepage", "2024-01-15", 1500),
      ("product", "2024-01-15", 800),
      ("checkout", "2024-01-15", 200),
      ("homepage", "2024-01-16", 1600),
      ("product", "2024-01-16", 850)
    ).toDF("page", "view_date", "view_count")

    // Register as managed tables in analytics database
    spark.sql("CREATE DATABASE IF NOT EXISTS analytics")
    userEvents.write.mode("overwrite").saveAsTable("analytics.user_events")
    pageViews.write.mode("overwrite").saveAsTable("analytics.page_views")

    spark.sql("CREATE DATABASE IF NOT EXISTS reporting")
    val dailyMetrics = Seq(
      ("2024-01-15", 5000, 150, 3.0),
      ("2024-01-16", 5200, 165, 3.17),
      ("2024-01-17", 4800, 140, 2.92)
    ).toDF("date", "total_users", "conversions", "conversion_rate")
    dailyMetrics.write.mode("overwrite").saveAsTable("reporting.daily_metrics")

    println("Sample data created successfully")
  }
